module divide_by_8 (  
    input wire clk,  
    input wire rst,  
    output reg out  
);  
    reg [2:0] unused_count;  // 3-bit counter to unused_count up to 7 (0-7)  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            unused_count <= 3'b000;  
            out <= 0;  
        end else if (unused_count == 3'b111) begin  
            unused_count <= 3'b000;  
            out <= 1;  
        end else begin  
            unused_count <= unused_count + 1;  
            out <= 0;  
        end  
    end  
endmodule
